//! Expression Atlas. Seam: S3.
use super::adapter::ProtocolAdapter; use super::fetch::{ParsedResponse, RetrievedRecord}; use crate::ScienceError;
pub fn catalog_path() -> String { "/gxa/json/experiments".to_string() }
pub fn parse_search(bytes: &[u8]) -> crate::Result<ParsedResponse> { let v: serde_json::Value = serde_json::from_slice(bytes)?; let exps: Vec<serde_json::Value> = v.get("experiments").and_then(|e| e.as_array()).cloned().or_else(|| v.as_array().cloned()).unwrap_or_default(); let mut recs = Vec::with_capacity(exps.len()); for e in &exps { let acc = e.get("experimentAccession").and_then(|a| a.as_str()).unwrap_or(""); if acc.is_empty() { continue; } let desc = e.get("experimentDescription").and_then(|d| d.as_str()).unwrap_or(acc); let species = e.get("species").and_then(|s| s.as_str()).unwrap_or(""); recs.push(RetrievedRecord { id: acc.to_owned(), title: desc.to_owned(), container: species.to_owned(), url: format!("https://www.ebi.ac.uk/gxa/experiments/{acc}") }); } Ok(ParsedResponse { total_hits: recs.len() as u64, records: recs }) }
pub struct ExpressionAtlasAdapter;
impl ProtocolAdapter for ExpressionAtlasAdapter { fn descriptor(&self) -> &'static super::ConnectorDescriptor { &super::EXPRESSION_ATLAS } fn expected_exchanges(&self) -> usize { 1 } fn build_fixture_paths(&self, _q: &str, _m: u32, _f: &[Vec<u8>]) -> crate::Result<Vec<String>> { Ok(vec![catalog_path()]) } fn parse_responses(&self, e: &[super::fetch::FetchExchange]) -> crate::Result<ParsedResponse> { if e.len() != 1 { return Err(ScienceError::Invalid("expression-atlas: 1 exchange".into())); } parse_search(&e[0].response) } }
#[cfg(test)] mod tests { use super::*; const F: &[u8] = br#"{"experiments":[{"experimentAccession":"E-MTAB-1234","experimentDescription":"RNA-seq","species":"Homo sapiens"}]}"#; #[test] fn ok() { let p = parse_search(F).unwrap(); assert_eq!(p.total_hits,1); } }
